154: static void socksstate(struct socks_state *sx, struct Curl_easy *data,
155:                        enum connect_t state
156: #ifdef DEBUG_AND_VERBOSE
157:                        , int lineno
158: #endif
159: )
160: {
161:   enum connect_t oldstate = sx->state;
162: #ifdef DEBUG_AND_VERBOSE
163:   /* synced with the state list in urldata.h */
164:   static const char * const socks_statename[] = {
165:     "INIT",
166:     "SOCKS_INIT",
167:     "SOCKS_SEND",
168:     "SOCKS_READ_INIT",
169:     "SOCKS_READ",
170:     "GSSAPI_INIT",
171:     "AUTH_INIT",
172:     "AUTH_SEND",
173:     "AUTH_READ",
174:     "REQ_INIT",
175:     "RESOLVING",
176:     "RESOLVED",
177:     "RESOLVE_REMOTE",
178:     "REQ_SEND",
